import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from 'react'
import { listCoverageRules } from '../api/client'
import type { CoverageRuleOut } from '../types/api'

type RulesContextValue = {
  rulesById: ReadonlyMap<string, CoverageRuleOut>
  loading: boolean
  error: string | null
}

const RulesContext = createContext<RulesContextValue | null>(null)

export function RulesProvider({ children }: { children: ReactNode }) {
  const [rules, setRules] = useState<CoverageRuleOut[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    listCoverageRules()
      .then(setRules)
      .catch((err: unknown) => {
        setError(err instanceof Error ? err.message : String(err))
      })
      .finally(() => setLoading(false))
  }, [])

  const rulesById = useMemo(
    () => new Map(rules.map((rule) => [rule.id, rule])),
    [rules],
  )

  return (
    <RulesContext.Provider value={{ rulesById, loading, error }}>
      {children}
    </RulesContext.Provider>
  )
}

export function useRules(): RulesContextValue {
  const ctx = useContext(RulesContext)
  if (!ctx) {
    throw new Error('useRules must be used within RulesProvider')
  }
  return ctx
}

export function useRule(ruleId: string | null | undefined): CoverageRuleOut | undefined {
  const { rulesById } = useRules()
  if (!ruleId) return undefined
  return rulesById.get(ruleId)
}

import { useRule } from '../context/RulesContext'
import { formatServiceType } from '../utils/format'

type RuleTooltipProps = {
  ruleId: string
}

function kindLabel(kind: string): string {
  return kind.replace(/_/g, ' ')
}

export function RuleTooltip({ ruleId }: RuleTooltipProps) {
  const rule = useRule(ruleId)

  if (!rule) {
    return (
      <span className="rule-ref">
        Rule: <code>{ruleId}</code>
      </span>
    )
  }

  return (
    <span className="rule-ref rule-ref--has-tooltip">
      Rule:{' '}
      <span className="rule-tooltip-anchor" tabIndex={0}>
        <code>{ruleId}</code>
        <span className="rule-tooltip" role="tooltip">
          <strong>{rule.policy_name}</strong>
          <span className="rule-tooltip__kind">
            {kindLabel(rule.kind)} · {formatServiceType(rule.service_type)}
          </span>
          <span className="rule-tooltip__body">{rule.description}</span>
          {rule.parameters_summary !== 'No parameters' && (
            <span className="rule-tooltip__meta">{rule.parameters_summary}</span>
          )}
        </span>
      </span>
    </span>
  )
}

